const rows = $input.all().map(({ json }) => json).filter(Boolean);
const toTime = (row) => {
  const value = row.submitted_at || row.submittedAt || row.created_at || row.createdAt || row.updated_at || row.updatedAt || '';
  const time = Date.parse(value);
  return Number.isFinite(time) ? time : 0;
};
const requests = rows
  .slice()
  .sort((a, b) => toTime(b) - toTime(a))
  .slice(0, 25)
  .map((row, index) => ({
    id: row.id ?? row.rowId ?? index + 1,
    submitted_at: row.submitted_at || row.submittedAt || '',
    applicant_name: row.applicant_name || row.applicantName || '',
    property_address: row.property_address || row.propertyAddress || '',
    project_type: row.project_type || row.projectType || '',
    specific_question: row.specific_question || row.specificQuestion || '',
    status: row.status || 'new',
    slug: row.slug || 'saybrook-zoning',
    jurisdiction: row.jurisdiction || 'Saybrook Township',
    email: row.email || '',
    phone: row.phone || '',
    preferred_contact: row.preferred_contact || row.preferredContact || '',
    project_summary: row.project_summary || row.projectSummary || '',
    ai_summary: row.ai_summary || row.aiSummary || '',
    source_answer: row.source_answer || row.sourceAnswer || '',
    source_citations_json: row.source_citations_json || '[]',
    attachments_json: row.attachments_json || '[]',
    chat_transcript_json: row.chat_transcript_json || '[]'
  }));
return [{ json: { ok: true, count: requests.length, requests, source: 'saybrook-zoning-trustee-requests' } }];
